// Unique "About This Service" content for individual service detail pages
// Replaces the generic duplicate paragraph that was hurting SEO

export const SERVICE_ABOUT: Record<string, string> = {
  // PLUMBING
  "water-heater-installation": "Water heater installation in the UAE involves more than just connecting pipes — unit sizing matters based on your household size, bathroom count, and whether you need a storage tank (50-80 liters for apartments, 80-120 liters for villas) or an instant tankless heater. Our plumbers supply units from Ariston, Midea, and other UAE-stocked brands, handle wall mounting with proper bracket load support, connect hot and cold water lines, install the pressure relief valve, and test for leaks before handover. We also remove and dispose of your old unit. Most apartment installations are completed in 2-3 hours. Villa installations with longer pipe runs may take half a day.",
  "water-heater-repair": "Common water heater problems in UAE homes include no hot water (usually a failed heating element or tripped thermostat), water not getting hot enough (sediment buildup or thermostat miscalibration), and tank leaks (corroded anode rod or tank bottom). Our technicians diagnose the issue on-site, carry replacement elements, thermostats, and anode rods for popular brands, and complete most repairs in a single visit. If the tank itself is corroded beyond repair, we provide a same-day replacement quote with installation included.",
  "leak-repair": "Water leaks in UAE apartments and villas range from visible drips under sinks to hidden pipe leaks inside walls that show up as damp patches or peeling paint. Our plumbers use pressure testing and moisture detection to pinpoint the exact leak location before cutting into walls or floors, minimizing damage and repair costs. Common fixes include pipe joint resealing, washer replacement, flexi-hose swap, and corroded pipe section replacement. Emergency leak calls in Dubai and Sharjah are prioritized for same-day response.",
  "drain-cleaning": "Blocked drains in UAE kitchens are usually caused by grease and food particle buildup, while bathroom drains clog from hair and soap residue. Our plumbers use mechanical drain snakes for standard blockages and hydro-jetting for severe or deep-line clogs that chemical cleaners can't reach. We also inspect drain condition and recommend preventive measures — like grease traps for kitchen sinks — to reduce repeat blockages. Floor drain cleaning in bathrooms and laundry rooms is included in our standard service.",
  "pipe-repair": "Pipe repairs in UAE buildings range from simple fixes like replacing a burst flexi-hose under a sink (20 minutes) to more involved work like cutting out and replacing a corroded galvanized pipe section with modern PPR or CPVC pipe (2-4 hours). Our plumbers carry fittings for all common pipe types found in UAE buildings — galvanized steel in older buildings, copper in mid-age construction, and PPR/CPVC in newer builds. We pressure-test after every repair to confirm the fix holds.",
  "faucet-repair": "A dripping faucet wastes up to 20 liters of water per day in the UAE. Most faucet repairs involve replacing the internal cartridge (for mixer taps) or rubber washer (for traditional taps). Our plumbers carry cartridges for popular brands like Grohe, Hansgrohe, andDERA. If the faucet body is corroded or cracked, we provide a replacement quote with same-visit installation. Repair typically takes 15-30 minutes per faucet.",
  "toilet-repair": "Toilet issues in UAE homes include continuous running water (usually a faulty fill valve or flapper), weak flush (blocked rim jets or low tank water level), and base leaks (failed wax ring seal). Our plumbers diagnose and fix most toilet problems in 30-60 minutes, carrying standard replacement parts on every service van. For older toilets with discontinued parts, we recommend full mechanism replacement rather than repeated patchwork repairs.",
  "sink-installation": "Kitchen and bathroom sink installation includes removing the old unit (if replacing), preparing the countertop cutout, mounting the sink (under-mount, top-mount, or vessel style), connecting the drain assembly with P-trap, installing the faucet, and testing for leaks. Our plumbers work with all counter materials — granite, marble, engineered stone, and laminate. Most sink installations are completed in 2-3 hours including cleanup.",
  "shower-installation": "Shower installation covers fitting the shower head and arm, installing the mixer valve (concealed or exposed), connecting hot and cold supply lines, setting up the floor drain, and sealing all joints. For shower enclosure upgrades, we coordinate glass panel installation and floor waterproofing. Our plumbers handle both simple showerhead swaps (30 minutes) and full shower system installations (half day).",
  // AC
  "ac-cleaning": "AC cleaning in the UAE is essential every 3-4 months given the extreme dust and humidity. Our service includes opening the indoor unit, removing and washing the filters, cleaning the evaporator coil with approved foam cleaner, flushing the condensate drain line to prevent water leaks, cleaning the blower wheel, and sanitizing the unit with anti-bacterial spray. For the outdoor condenser, we rinse the coil fins with pressurized water to remove sand and debris that reduce cooling efficiency. Each unit service takes 30-45 minutes.",
  "ac-gas-refill": "If your AC is running but not cooling properly, low refrigerant gas is often the cause. Our technicians connect gauges to measure your system's pressure, identify any gas leaks (which must be fixed before refilling), and top up with the correct refrigerant type — R410A for newer units or R22 for older systems. We also check the compressor amperage to confirm the system is operating within rated parameters after the refill. A standard gas refill takes 30-60 minutes per unit.",
  "ac-not-cooling-repair": "When your AC runs but blows warm or room-temperature air, the cause could be low gas, a dirty evaporator coil blocking airflow, a faulty compressor capacitor, a stuck expansion valve, or a malfunctioning thermostat sensor. Our technicians systematically check each component to identify the actual fault rather than guessing. Common fixes include capacitor replacement, coil cleaning, gas refill, and thermostat recalibration — most completed in a single visit.",
  "ac-water-leak-repair": "Water dripping from your indoor AC unit is almost always caused by a clogged condensate drain line — dust, algae, and mineral deposits block the pipe over time, causing water to back up into the drain pan and overflow. Our fix involves clearing the drain using compressed air or a wet vacuum, flushing the line with cleaning solution, and checking the drain pan for cracks. In some cases, the drain pan itself needs replacement. This is a 30-45 minute repair.",
  "ac-annual-maintenance": "Our annual AC maintenance plan includes 4 quarterly servicing visits covering filter wash, coil cleaning, gas pressure check, drain flush, and performance testing on every unit in your property. Between visits, you get priority scheduling for any AC issues, with emergency calls responded to within 4 hours. The plan pays for itself by preventing breakdowns, extending unit lifespan, and maintaining cooling efficiency that reduces electricity bills by 10-20%.",
  "ac-filter-cleaning": "AC filters should be cleaned monthly during UAE summers when AC runs 16-20 hours daily. Clogged filters reduce airflow by up to 50%, forcing the compressor to work harder and increasing electricity consumption. Our technicians remove each filter, wash with mild detergent, dry thoroughly, and reinstall — checking filter condition and recommending replacement for filters that are torn or permanently discolored. Takes 10-15 minutes per unit.",
  "split-ac-installation": "Split AC installation includes mounting the indoor unit bracket on the wall, drilling the pipe hole through the exterior wall, routing copper pipes and electrical cable to the outdoor unit location, mounting the outdoor condenser unit on a bracket or ground pad, connecting refrigerant lines, pressure testing for leaks, vacuuming the system, charging with refrigerant gas, and testing cooling performance. Standard installation in a pre-piped room takes 2-3 hours; new installations requiring pipe routing take 4-6 hours.",
  "ac-duct-cleaning": "AC duct cleaning removes accumulated dust, mold spores, and debris from your ductwork that circulate through your home every time the AC runs. Our process includes inspection with a duct camera, mechanical brushing of duct interiors, HEPA-filtered vacuum extraction of loosened debris, coil cleaning at the air handling unit, and anti-microbial treatment of duct surfaces. A standard 2-bedroom apartment duct cleaning takes 3-4 hours; villas with more extensive ductwork take 5-8 hours.",
  // CLEANING
  "deep-home-cleaning": "Deep home cleaning goes far beyond regular surface cleaning — we target the areas that accumulate grime over weeks and months but get missed in routine cleaning. This includes inside kitchen cabinets and behind appliances, bathroom tile grout scrubbing and descaling, window track and frame cleaning, skirting board and door frame dusting, light fixture cleaning, under-furniture vacuuming, and balcony floor scrubbing. A 2-bedroom apartment deep clean takes 4-6 hours with a 2-person team; villas take 6-10 hours depending on size.",
  "move-in-move-out-cleaning": "Move-in and move-out cleaning is designed to meet landlord handover standards in the UAE. We clean every surface a property inspector would check — kitchen cabinets (inside and out), appliance exteriors, bathroom fixtures and tiles, all floors, window glass and frames, wardrobe interiors, balcony and storage areas, and door handles and light switches. Many landlords in Dubai and Sharjah require professional cleaning receipts as part of the deposit return process — we provide these on completion.",
  "sofa-cleaning": "Fabric sofas in UAE homes collect dust faster than in milder climates due to desert sand particles and AC-circulated dust. Our steam cleaning method injects hot water and cleaning solution into the fabric under pressure, then immediately extracts it along with embedded dirt, allergens, and bacteria. The result is a sofa that looks refreshed, smells clean, and dries within 2-4 hours. For leather sofas, we use a separate pH-balanced cleaning and conditioning process that protects the material from cracking.",
  "carpet-cleaning": "UAE carpets take a beating from fine desert sand that works its way deep into fibers, past what regular vacuuming can reach. Our hot-water extraction method forces cleaning solution through the carpet pile and immediately vacuums it out, pulling up embedded sand, dust mites, and stains from the carpet backing. This method is recommended by most carpet manufacturers and significantly extends carpet lifespan compared to dry-powder cleaning. A standard room carpet takes 20-30 minutes to clean and 3-4 hours to fully dry.",
  "mattress-cleaning": "Mattresses accumulate sweat, dead skin cells, and dust mites over time — a typical mattress can harbor millions of dust mites after just two years of use. Our cleaning process includes thorough vacuuming with a HEPA-filter machine, targeted stain treatment for sweat marks and spills, UV-C light sanitization to kill bacteria and mites, and optional anti-allergen spray treatment. Most single and double mattresses take 30-45 minutes to clean and can be slept on the same evening.",
  "villa-cleaning": "Villa cleaning covers significantly more ground than apartment cleaning — multiple bedrooms, 3-5 bathrooms, larger kitchen with more cabinet space, maid's room, storage areas, and sometimes a garage, garden, and pool deck. Our villa teams arrive with 2-3 cleaners and commercial-grade equipment to complete the job efficiently. We customize the cleaning checklist based on your villa's layout and which areas need the most attention, rather than applying a rigid apartment-style package to a completely different property type.",
  "office-cleaning": "Office cleaning requirements differ from home cleaning — desks need wiping without disturbing papers and equipment, communal kitchens need daily sanitization, washrooms need restocking and deep cleaning, and floor cleaning needs to happen during off-hours to avoid disrupting work. We offer early morning (6-8 AM), evening (after 6 PM), and weekend cleaning slots specifically for office clients. Recurring plans include daily, twice-weekly, and weekly options with consistent teams assigned to your office.",
  "apartment-cleaning": "Apartment cleaning covers kitchen (counters, stovetop, sink, cabinet fronts), bathroom (toilet, shower, mirror, floor), bedroom (bed making, surface dusting, floor), living area (furniture dusting, floor mopping), and general tidying. Our cleaners follow a room-by-room checklist to ensure nothing gets missed. Studio and 1-bedroom apartments take 2-3 hours; 2-bedroom units take 3-4 hours. We bring all cleaning supplies and equipment — you don't need to provide anything.",
  "window-cleaning": "Window cleaning in the UAE needs to be done more frequently than in milder climates due to sand and dust deposits that build up quickly, especially after sandstorms. Our service covers interior glass cleaning, exterior glass cleaning (for accessible windows), frame and track cleaning to remove sand buildup, and squeegee finishing for streak-free results. For high-rise exterior windows, we coordinate with building management for rope access or BMU (building maintenance unit) scheduling.",
  "curtain-cleaning": "Curtains in UAE homes act as dust filters, trapping fine sand particles and AC-circulated dust in their fabric folds. Our curtain cleaning process includes careful removal from rods or tracks, fabric type assessment (different methods for sheer, blackout, and lined curtains), professional washing or dry cleaning as appropriate, pressing or steaming to remove wrinkles, and reinstallation on your existing hardware. Turnaround is typically 24-48 hours for standard curtains.",
  "post-construction-cleaning": "Post-construction cleaning removes the fine dust, paint splatter, adhesive residue, and debris left behind after renovation or building work. This requires different equipment and techniques than regular cleaning — HEPA-filter vacuums for concrete dust (which regular vacuums just recirculate), scraper tools for paint and adhesive on glass and tiles, and industrial degreasers for construction grime on fixtures. A standard apartment post-construction clean takes 6-8 hours; villas take 1-2 full days.",
  "water-tank-cleaning": "Water tank cleaning is recommended every 6 months in the UAE to prevent sediment buildup, algae growth, and bacterial contamination. Our process includes draining the tank completely, scrubbing interior walls and floor to remove sediment and biofilm, disinfecting with chlorine solution at the correct concentration, rinsing thoroughly, and refilling. We provide a cleaning certificate that many Dubai and Sharjah municipalities require for residential and commercial properties.",
  // ELECTRICAL
  "light-installation": "Light installation covers ceiling-mounted fixtures, wall sconces, recessed downlights, spotlights, and outdoor lights. Our electricians handle the full process — turning off the circuit, removing old fixtures, checking wire condition, connecting the new light (live, neutral, earth), securing the mounting, and testing. For new installation points where no wiring exists, we route cable from the nearest junction box or DB panel. Standard light fitting takes 20-30 minutes; new wiring points take 1-2 hours.",
  "db-box-work": "Distribution board (DB box) work includes upgrading old fuse boxes to modern MCB/RCCB panels, adding new circuit breakers for additional loads, labeling circuits for easy identification, installing earth leakage protection devices, and balancing loads across phases. Many older UAE buildings still have outdated DB boxes that trip frequently or lack proper earth leakage protection — upgrading is both a safety improvement and a convenience fix. Standard DB upgrade takes 3-5 hours.",
  "chandelier-installation": "Chandelier installation requires a ceiling anchor rated for the fixture weight (some chandeliers exceed 30kg), proper electrical connection with a junction box, and careful assembly of the chandelier components. For heavy fixtures, we install a ceiling plate with expansion bolts into concrete. Our electricians also set up dimmer switches if requested and test all lamp positions. Standard chandelier installation takes 1-3 hours depending on complexity.",
  // HANDYMAN
  "furniture-assembly": "Flat-pack furniture assembly covers wardrobes, desks, bed frames, bookshelves, TV units, and dining tables from IKEA, Home Centre, Pan Emirates, and other UAE retailers. Our handymen follow manufacturer instructions precisely, use proper tools (not just the included Allen key), and ensure all fixings are tight and the piece is level and stable. A standard wardrobe takes 1.5-2.5 hours; a bed frame 1-1.5 hours; a desk 45-60 minutes.",
  "tv-mounting": "TV wall mounting includes selecting the right bracket type for your TV size and wall material (concrete, drywall, or block), drilling with appropriate anchors, mounting the bracket, hanging the TV, connecting cables, and concealing wires in a cable management channel or behind-wall conduit if requested. We bring brackets in common sizes or install customer-supplied brackets. Standard TV mounting takes 45-90 minutes.",
  "interior-painting": "Interior painting in UAE apartments and villas includes wall preparation (filling holes, sanding rough spots, cleaning surfaces), masking tape protection for door frames, windows, and switches, primer coat where needed, and two finish coats of emulsion paint. We use Jotun, National Paints, or customer-specified brands. A standard bedroom takes 1 day; a full 2-bedroom apartment takes 3-4 days. All furniture is covered and floors protected during work.",
  // PEST CONTROL
  "general-pest-treatment": "General pest treatment covers the most common household pests in the UAE — cockroaches, ants, silverfish, and spiders. Our treatment includes spraying residual insecticide along baseboards, under sinks, behind appliances, and around entry points, plus applying gel bait in kitchen cabinets and bathroom fixtures where cockroaches harbor. One treatment typically provides 2-3 months of protection. We use municipality-approved, low-toxicity products safe for homes with children and pets.",
  "cockroach-control": "Cockroach control in UAE homes uses a combination of gel bait (placed in cabinet hinges, behind appliances, and near pipe entry points) and residual spray (along baseboards and under sinks). Gel bait is particularly effective because cockroaches eat it and carry it back to the nest, killing colony members that never directly contact the treated area. Our treatment provides 2-3 months of control. For severe infestations, we recommend a follow-up visit after 2 weeks.",
  "bed-bug-treatment": "Bed bug treatment requires a different approach than general pest control — bed bugs are resistant to many standard insecticides and hide in mattress seams, bed frame joints, and headboard crevices. Our treatment combines targeted spray application with heat treatment of the mattress and bed frame, plus treatment of adjacent furniture and baseboards. We recommend a follow-up inspection 2 weeks after treatment to confirm all life stages (including eggs) have been eliminated.",
  "termite-control": "Termite control in the UAE targets subterranean termites that enter buildings from soil contact points — common in villas with ground-floor wooden fixtures, door frames, and furniture. Our treatment options include soil barrier treatment (injecting termiticide into the soil around the building perimeter), bait station installation (monitoring stations that detect and eliminate colonies), and spot treatment for active infestations in specific wooden elements. Treatment choice depends on property type and infestation severity.",
  // MOVERS
  "apartment-moving": "Apartment moving includes furniture disassembly (beds, wardrobes, dining tables), protective wrapping of all items (bubble wrap for fragile items, blankets for furniture), loading onto our vehicles with proper securing, transport to the new location, unloading, and furniture reassembly. We provide all packing materials. A studio move typically takes 3-4 hours and uses a small truck; a 2-bedroom apartment takes 5-7 hours and uses a larger vehicle. We handle moves within Dubai, between emirates, and across the UAE.",
  "villa-moving": "Villa moving is a larger-scale operation covering multiple rooms, outdoor furniture, garden items, and sometimes a garage full of stored items. We deploy 4-6 movers with a large truck (or two trucks for larger villas), with a dedicated supervisor coordinating the packing sequence, loading order, and reassembly at the destination. Heavy items like safes, pianos, and gym equipment require additional handling equipment. A standard 3-bedroom villa move takes a full day.",
  // GARDEN
  "pool-cleaning": "Pool cleaning includes skimming the surface for leaves and debris, vacuuming the pool floor, brushing walls and tile lines, cleaning the skimmer basket and pump strainer, testing and balancing water chemistry (pH, chlorine, alkalinity), and inspecting the pump and filter for proper operation. Regular cleaning prevents algae growth, keeps water safe for swimming, and extends equipment lifespan. Our standard visit takes 45-60 minutes for residential pools.",
  "pool-maintenance": "Monthly pool maintenance goes beyond basic cleaning — it includes filter backwashing or cartridge cleaning, pump performance check, salt chlorinator cell inspection (if applicable), equipment lubrication, tile calcium deposit removal, and seasonal adjustments to chemical dosing as water temperature changes. We provide a written condition report after each visit so you can track your pool system's health over time.",
  // BUILDING MAINTENANCE
  "property-snagging": "Property snagging is a systematic inspection of a newly built or renovated property to identify defects before you accept handover from the developer. Our inspectors check 200+ points including paint finish quality, tile alignment and grouting, plumbing fixtures and water pressure, electrical outlets and switches, AC cooling performance and drainage, door and window operation, kitchen cabinet alignment, and balcony drainage. You receive a detailed report with photos within 24 hours, which you submit to the developer for rectification.",
  "residential-amc": "Our residential AMC bundles the maintenance services a typical UAE home needs throughout the year into one predictable annual contract. Standard coverage includes quarterly AC servicing for all units, bi-annual plumbing inspection, annual electrical safety check, quarterly pest control treatment, and a set number of emergency callouts per month. The plan eliminates the hassle of booking individual services and typically costs 20-30% less than paying for the same services separately.",

  // AC - remaining
  "ac-compressor-repair": "AC compressor failure is the most expensive AC repair — symptoms include the outdoor unit not starting, a clicking sound at startup, or the system tripping the circuit breaker. Our technicians test the compressor windings, capacitor, and relay before recommending repair or replacement. Common fixes include capacitor swap (AED 150-250) and relay replacement. Full compressor replacement is quoted separately based on unit tonnage and brand, including refrigerant recharge and leak testing.",
  "ac-thermostat-repair": "A faulty thermostat causes the AC to overcool, undercool, or cycle on and off unpredictably. Our technicians test sensor accuracy, recalibrate the thermostat, or replace the unit entirely if it is beyond repair. We work with both wired wall-mounted thermostats and wireless remote-control systems. For smart thermostat upgrades, we handle wiring compatibility checks and installation including WiFi setup and app configuration.",
  "central-ac-service": "Central AC servicing covers the air handling unit (AHU), supply and return ductwork, thermostat calibration, and chilled water valve or DX system checks depending on your building type. Our HVAC technicians inspect blower motor performance, check belt tension, clean coils, verify refrigerant charge, and test airflow at each supply vent. For villa central systems with multiple zones, we ensure balanced cooling distribution across all rooms.",
  "window-ac-installation": "Window AC installation includes measuring the window opening, fitting the AC unit into the sleeve or frame, sealing gaps with weatherstrip foam to prevent air and insect entry, connecting electrical supply (dedicated outlet recommended), and testing cooling output. For windows without existing sleeves, we fabricate a mounting frame. Units are angled slightly outward to ensure condensate drains externally rather than inside the room.",
  // CLEANING - remaining
  "house-cleaning": "House cleaning covers a systematic room-by-room clean of your home — kitchen surfaces and sink, bathroom sanitization, bedroom dusting and bed making, living area floor mopping and furniture wipe-down, and general tidying. Our cleaners follow a checklist to ensure consistency every visit. Suitable for regular maintenance between deep cleans. Standard 2-3 bedroom house takes 3-4 hours with one cleaner.",
  "weekly-cleaning": "Weekly cleaning maintains your home at a consistent standard without the buildup that happens between monthly or bi-monthly cleans. Each visit covers kitchen wipe-down, bathroom sanitization, floor mopping, surface dusting, trash removal, and general tidying. Having the same cleaner assigned each week means they learn your home layout and preferences, becoming more efficient with every visit.",
  "monthly-cleaning": "Monthly cleaning is a thorough session that sits between regular weekly upkeep and a full deep clean. It includes everything in a weekly clean plus additional tasks like inside-microwave cleaning, mirror polishing, baseboard dusting, fan blade cleaning, and door handle sanitization. Ideal for homes that stay relatively tidy but need a detailed monthly refresh to prevent gradual dust and grime accumulation.",
  "spring-cleaning": "Spring cleaning is a seasonal reset for your entire home — every room gets deep attention including areas typically skipped in regular cleaning. We clean inside wardrobes and drawers, wash curtains or vacuum them in place, clean window tracks and frames, scrub tile grout, polish metal fixtures, dust behind and under all furniture, and clean light fixtures. Takes 6-10 hours depending on home size with a 2-3 person team.",
  "kitchen-deep-cleaning": "Kitchen deep cleaning targets the heaviest grease and grime zones — exhaust hood and filter degreasing, oven interior cleaning, stovetop burner and grate scrubbing, countertop disinfection, cabinet exterior and handle cleaning, sink and drain descaling, tile backsplash grout cleaning, and refrigerator exterior wipe-down. Optional add-on: inside-fridge cleaning with shelf removal. Takes 2-3 hours for a standard kitchen.",
  "bathroom-deep-cleaning": "Bathroom deep cleaning goes beyond daily wipe-downs to tackle mineral scale on shower glass, grout mold and discoloration, toilet descaling including under the rim, vanity cabinet cleaning inside and out, mirror streak-free polishing, exhaust fan dust removal, and floor scrubbing into corners and behind the toilet. Hard water stains are treated with specialized descaling agents. Takes 1-1.5 hours per bathroom.",
  "home-disinfection": "Home disinfection uses EPA-approved antimicrobial fogging or spray treatment covering all room surfaces, high-touch points (door handles, light switches, remotes, countertops), soft furnishings, and AC vents. Our disinfection products are effective against bacteria, viruses, and fungi while being safe for homes with children and pets after the recommended drying time (typically 30-60 minutes). Certificate of disinfection provided on completion.",
  "office-disinfection": "Office disinfection covers workstations, shared equipment (printers, phones, coffee machines), meeting rooms, reception areas, washrooms, and kitchen/pantry surfaces using commercial-grade antimicrobial products. We work during off-hours or weekends to minimize disruption. Treatment includes electrostatic spraying for even coverage on all surfaces including hard-to-reach areas. Ideal for periodic sanitization or after a confirmed illness in the office.",
  "villa-sanitization": "Villa sanitization is a room-by-room antimicrobial treatment covering all living spaces, bathrooms, kitchen, maid's room, and outdoor sitting areas. We fog or spray each room with EPA-approved disinfectant, paying extra attention to AC vents (which circulate air throughout the villa), bathroom fixtures, kitchen surfaces, and door handles. Service takes 2-4 hours depending on villa size, with re-entry safe after 1 hour drying time.",
  "facade-cleaning": "Building facade cleaning removes accumulated dust, pollution stains, and watermarks from exterior walls and glass curtain walls. We use rope access (harness-based) or boom lift methods depending on building height and access conditions. Cleaning agents are selected based on facade material — glass, aluminum cladding, painted concrete, or natural stone each require different products to avoid damage. Quoted per square meter based on building height and facade type.",
  "pressure-washing": "Pressure washing uses high-pressure water jets (1500-3000 PSI) to clean driveways, parking areas, building exteriors, pool decks, garden walls, and paved walkways. Effective at removing oil stains, tire marks, algae, moss, and embedded dirt that regular mopping cannot shift. Our operators adjust pressure settings based on surface type — lower for painted surfaces and wood, higher for concrete and interlocking tiles. Most residential jobs completed in 2-4 hours.",
  "solar-panel-cleaning": "Dirty solar panels lose 15-25% of their energy output due to dust, bird droppings, and mineral deposits blocking sunlight. Our cleaning uses deionized water and soft brushes to remove all surface contamination without scratching the glass or damaging panel seals. We inspect panel condition during cleaning and report any cracked glass, loose connections, or frame damage. Recommended every 3-6 months in the UAE's dusty climate.",
  "event-cleaning": "Event cleaning covers pre-event setup cleaning (venue floor mopping, furniture dusting, washroom preparation) and post-event deep cleanup (trash removal, spill treatment, floor scrubbing, furniture rearrangement, washroom restoration). We scale team size based on venue size and event type — from home parties needing 2 cleaners to large venue events needing 6-8. Post-event cleaning typically starts immediately after guest departure.",
  "event-setup-support": "Event setup support covers chair and table arrangement per your layout plan, decoration installation assistance, signage placement, AV equipment positioning, and general venue preparation. Post-event, we handle teardown, furniture return to storage positions, decoration removal, and venue restoration to its pre-event condition. Available for home events, corporate functions, and venue-based gatherings.",
  "retail-cleaning": "Retail shop cleaning maintains a presentable shopping environment — glass storefront polishing, display shelf dusting, fitting room tidying, floor mopping (tile, marble, or vinyl), counter sanitization, and customer washroom cleaning. We schedule cleaning during early morning hours before opening or after closing to avoid customer disruption. Weekly and daily recurring plans available for retail businesses.",
  "warehouse-cleaning": "Warehouse cleaning handles large-scale floor scrubbing (concrete, epoxy, or polished surfaces), racking and shelf dust-down, loading bay washdown, office area within warehouse cleaning, and washroom maintenance. We use ride-on floor scrubbers for large areas and pressure washers for loading zones. Cleaning is scheduled during off-peak hours to avoid disrupting warehouse operations.",
  // ELECTRICAL - remaining
  "power-socket-repair": "Sparking, loose, or non-functioning power sockets are a fire hazard. Our electricians test the outlet circuit, replace the socket faceplate and internal mechanism, check wire connections for heat damage or looseness, and ensure proper earthing. For damaged wiring behind the socket, we splice in new cable or route a new wire from the DB panel. Most socket repairs take 15-30 minutes per outlet.",
  "circuit-breaker-repair": "Frequent circuit breaker tripping indicates an overloaded circuit, short circuit, or ground fault. Our electricians identify which circuit is tripping, test for faults using a multimeter and insulation resistance tester, and replace faulty MCBs or RCCBs. We also check if the issue is caused by a specific appliance drawing excessive current. DB panel assessment and breaker replacement typically takes 1-2 hours.",
  "electrical-fault-finding": "Electrical fault finding uses systematic circuit testing to locate hidden wiring faults, intermittent short circuits, and earth leakage problems. Our electricians use insulation resistance testers, circuit tracers, and thermal imaging to pinpoint the exact fault location, minimizing the need to open walls. Common faults include damaged wiring from renovation work, water-damaged connections, and rodent-chewed cables in ceiling voids.",
  "ceiling-fan-installation": "Ceiling fan installation includes mounting the ceiling bracket (with appropriate anchors for concrete or drywall ceilings), assembling fan blades and motor housing, wiring the speed controller or remote receiver, and balancing the fan to prevent wobble. For heavy fans exceeding 15kg, we install reinforced ceiling anchors. We also set up wall-mounted speed controllers or wireless remote systems as needed. Standard installation takes 1-2 hours.",
  "exhaust-fan-installation": "Exhaust fan installation in kitchens and bathrooms includes cutting the wall or ceiling opening (if not pre-existing), mounting the fan unit, connecting to the electrical supply, and routing the exhaust duct to the building exterior or common duct shaft. For bathrooms, we recommend humidity-sensing fans that activate automatically when moisture levels rise. Installation takes 1-3 hours depending on duct routing complexity.",
  "wiring-rewiring": "Partial or full property rewiring replaces old, potentially unsafe cables with modern fire-rated wiring to current UAE electrical code. This includes running new cables through conduits, replacing the DB panel if needed, installing new outlets and switches, and testing the complete installation with an insulation resistance test. Rewiring is typically needed for buildings over 20 years old or after detecting frequent electrical faults.",
  // HANDYMAN - remaining
  "shelf-installation": "Shelf installation covers floating shelves, bracket-mounted shelves, display ledges, and built-in shelving units. Our handymen use appropriate wall anchors for your wall type (concrete, block, or drywall), ensure level alignment with a laser level, and test load capacity before finishing. Multiple shelves in the same room are aligned consistently. Typical installation takes 20-40 minutes per shelf.",
  "door-repair": "Common door problems include sticking or dragging on the floor (hinge adjustment or bottom trim), loose handles (tightening or mechanism replacement), misaligned latch (striker plate repositioning), and difficulty closing (frame warping or hinge wear). Our handymen diagnose the specific issue and fix it on-site. Most door repairs take 15-45 minutes per door.",
  "lock-installation": "Lock installation covers cylinder locks, deadbolts, smart locks, and padlocks for doors and gates. Our handymen drill the lock mortise, install the mechanism, fit the strike plate on the door frame, and test key operation and bolt alignment. For smart lock installations, we handle the wiring, battery setup, and initial code or app configuration. Standard lock installation takes 30-60 minutes.",
  "curtain-installation": "Curtain installation includes mounting rods, tracks, or motorized rail systems to the wall or ceiling, ensuring level alignment, and hanging the curtain fabric. For heavy curtains (blackout or layered), we use reinforced brackets rated for the weight. Motorized curtain tracks require electrical connection to a nearby outlet or hardwired to a wall switch. Standard rod installation takes 30-45 minutes per window.",
  "custom-carpentry": "Custom carpentry covers built-in shelving, closet modifications, kitchen cabinet additions, vanity units, TV wall units, under-stair storage, and bespoke wooden fixtures. Our carpenters work from measurements and design sketches to build pieces that fit your exact space. Materials include solid wood, MDF, plywood, and melamine-faced board depending on application and budget. Quote provided after on-site measurement visit.",
  "cabinet-repair": "Cabinet repair fixes common issues like loose hinges (causing doors to sag or not close properly), broken drawer runners (slides that stick or fall off track), delaminating surfaces (peeling veneer or melamine), and water-damaged bases (common under kitchen sinks). We carry standard hinge sizes, drawer slides, and edge banding for on-site repair. Most cabinet repairs completed in 30-60 minutes per unit.",
  "door-replacement": "Door replacement includes removing the old door from its hinges, preparing the frame for the new door (adjusting if sizes differ), hanging the new door with appropriate hinges, installing the handle and lock mechanism, and adjusting the strike plate for smooth closing. We supply standard interior doors or install customer-purchased doors. Gap weatherstrip sealing included for exterior doors. Takes 1-2 hours per door.",
  "exterior-painting": "Exterior painting for UAE buildings requires UV-resistant, weather-grade paint that withstands intense sun, occasional rain, and sandstorms. Our process includes pressure washing the surface, scraping loose old paint, filling cracks and holes, applying primer on bare areas, and rolling or spraying two coats of exterior emulsion. Scaffold or ladder setup is included for multi-story facades. A standard villa exterior takes 4-7 days with a 2-3 painter team.",
  "touch-up-painting": "Touch-up painting covers scuff marks, nail holes, minor scratches, and small damaged areas on interior walls without repainting the entire room. We color-match using the existing paint (or bring a color fan deck to find the closest match), apply filler to any holes, sand smooth, and apply paint only to the affected areas, blending edges to avoid visible patch lines. Ideal for move-out deposit returns and post-furniture-rearrangement fixes.",
  "wallpaper-installation": "Wallpaper installation includes surface preparation (cleaning, sanding rough spots, applying sizing primer), precise measurement and cutting of wallpaper panels, adhesive application (paste-the-wall or paste-the-paper depending on type), careful hanging with pattern alignment across panels, trimming at ceiling, floor, and around outlets, and roller smoothing to remove air bubbles. We work with vinyl, non-woven, fabric-backed, and peel-and-stick wallpapers. Standard room takes 4-6 hours.",
  // RENOVATION - remaining
  "kitchen-renovation": "Kitchen renovation covers layout redesign, cabinet supply and installation, countertop fabrication and fitting (granite, quartz, or solid surface), backsplash tiling, plumbing relocation for sink and dishwasher, electrical additions for new appliances, under-cabinet lighting, and hardware finishing. We manage the full project from design consultation through completion, coordinating carpenters, plumbers, electricians, and tilers. Typical kitchen renovation takes 2-4 weeks.",
  "bathroom-renovation": "Bathroom renovation includes fixture removal, waterproof membrane application (critical for UAE's warm climate), wall and floor tiling, shower enclosure or bathtub installation, vanity and mirror fitting, toilet replacement, plumbing connections, exhaust fan installation, and lighting upgrade. We handle the complete demolition-to-handover process. Standard bathroom renovation takes 5-10 days depending on scope.",
  "full-apartment-renovation": "Full apartment renovation transforms your space from floor to ceiling — new flooring (tile, wood, or vinyl), wall preparation and painting, kitchen and bathroom refurbishment, electrical upgrades, AC duct cleaning, lighting replacement, and fixture modernization. We provide a fixed project quote after detailed site survey, manage all trades (painter, tiler, plumber, electrician, carpenter), and hand over a ready-to-move-in property. Timeline: 3-8 weeks depending on apartment size.",
  "villa-renovation": "Villa renovation is a multi-phase project covering structural modifications (if approved), complete interior finishing, MEP system upgrades (AC, plumbing, electrical), kitchen and bathroom remodeling, flooring, painting, garden and outdoor area improvement, and smart home integration. We assign a dedicated project manager who coordinates 5-8 trades, manages material procurement, and provides weekly progress reports. Timeline: 2-6 months depending on scope.",
  "office-fit-out": "Office fit-out transforms a bare shell or existing office into a functional workspace — gypsum partition walls for room division, false ceiling with integrated lighting, raised flooring for cable management, networking and data point installation, AC duct modifications, reception desk and workstation setup, meeting room construction, and pantry plumbing. We handle municipality approvals, fire safety compliance, and final inspection coordination.",
  "retail-fit-out": "Retail fit-out covers shopfront fabrication and installation, interior display unit construction, point-of-sale counter, fitting room setup, storage area organization, lighting design and installation, flooring, wall finishes, signage, and security system setup. We work with retail brands to match corporate design guidelines and ensure the finished space meets municipality licensing requirements.",
  "restaurant-fit-out": "Restaurant fit-out is a specialized project covering commercial kitchen hood and exhaust system, grease trap installation, gas connection, cold room or walk-in chiller setup, dining area construction, bar area plumbing and electrical, washroom facilities, fire suppression system, and municipality food safety compliance. We manage the full process from civil works through final health inspection and license approval.",
  "gypsum-partition": "Gypsum board partitions create room divisions, office cubicles, and storage enclosures without permanent construction. Our installation includes metal framing (galvanized steel tracks and studs), gypsum board fixing with proper screw patterns, joint taping and mudding for seamless finish, and final sanding ready for paint. Sound insulation (mineral wool) and moisture-resistant boards available for bathrooms. Standard partition takes 1-2 days per 10 linear meters.",
  "ceiling-work": "False ceiling installation options include gypsum board (smooth, paintable finish), suspended grid with mineral fiber tiles (easy maintenance access), stretch ceiling (modern seamless look), and wooden ceiling panels (decorative). Our teams handle the metal framework, board or tile installation, recessed light cutouts, AC vent integration, and finishing. Gypsum ceilings take 2-4 days for a standard room; grid ceilings are faster at 1-2 days.",
  "tiling": "Tile installation covers floor and wall tiling in bathrooms, kitchens, balconies, and living areas. Our tilers handle surface preparation, waterproof membrane application (for wet areas), adhesive application, tile laying with consistent spacer gaps, grouting, and edge trim finishing. We work with all tile types — ceramic, porcelain, natural stone, large-format, mosaic, and patterned tiles. Rate is per square meter, with cutouts for outlets and fixtures included.",
  "flooring": "Flooring installation covers vinyl plank (click-lock or glue-down), laminate, engineered wood, natural hardwood, porcelain tile, and marble. Each material requires different subfloor preparation, adhesive type, and installation technique. Our teams handle furniture moving (if needed), old flooring removal, subfloor leveling, moisture barrier installation, flooring laying, skirting board fitting, and threshold transition strips. Most rooms completed in 1 day.",
  "masonry": "Masonry work covers concrete block wall construction, brick laying, plastering and rendering, structural patching and crack repair, boundary wall building, and retaining wall construction. Our masons work with standard concrete blocks, thermalite blocks, and decorative stone cladding. All structural work follows UAE building codes. We handle both minor patch jobs (half day) and full wall construction projects (multiple days).",
  "waterproofing": "Waterproofing prevents water penetration through roofs, bathroom floors, terraces, and basement walls — the most common cause of structural damage in UAE buildings. We apply bituminous membrane, polyurethane liquid membrane, or cementitious waterproof coating depending on the application. Bathroom waterproofing includes floor-to-wall membrane application with drain collar sealing, tested with 48-hour water ponding before tiling. Roof waterproofing includes thermal insulation layer.",
  "glass-work": "Glass work covers shower enclosure installation (frameless, semi-frameless, or framed), glass partition walls for offices, mirror installation and replacement, glass balustrade panels, glass door fitting, and broken window glass replacement. We use tempered safety glass (6-12mm) for all structural applications. Measurements are taken on-site, glass is fabricated to exact dimensions, and installation includes hardware, seals, and silicone finishing.",
  "aluminum-work": "Aluminum work covers window frame fabrication and installation, door frames, kitchen cabinet frames, curtain wall sections, pergola structures, and cladding panels. We manufacture custom aluminum profiles to fit your exact openings, powder-coat in your chosen color, install with proper weatherseal gaskets, and adjust for smooth operation. Common jobs include replacing old single-pane windows with double-glazed aluminum frames for better insulation.",
  // PEST CONTROL - remaining
  "ant-control": "Ant control targets the colony source, not just visible trails. Our technicians trace ant trails back to entry points, apply gel bait that worker ants carry to the queen (eliminating the colony from within), and spray perimeter barriers around the building foundation to prevent re-entry. For indoor ant problems in kitchens, we seal visible entry gaps and apply bait stations in concealed locations. Treatment provides 2-3 months of control.",
  "spider-control": "Spider control involves web removal from ceilings, corners, window frames, and exterior walls, followed by residual spray application in harboring areas. We also treat the outdoor perimeter where spiders commonly build webs — around exterior lights (which attract insects that spiders feed on), fence lines, and garden structures. Reducing outdoor lighting near entry points and sealing gaps helps prevent recurrence.",
  "rodent-control": "Rodent control uses a combination of snap traps, bait stations, and exclusion work (sealing entry points). Our technicians identify entry routes by inspecting gnaw marks, droppings, and grease trails, then place tamper-resistant bait stations in strategic locations and seal gaps around pipes, cables, and door frames. For active infestations, we recommend weekly monitoring visits for 4-6 weeks to confirm elimination before switching to monthly prevention.",
  "mosquito-control": "Mosquito control combines larvicide treatment in standing water sources (plant saucers, AC drip trays, garden water features, blocked drains) with adult mosquito fogging in outdoor living and garden areas. Our technicians identify and treat all potential breeding sites on your property. For ongoing protection, we recommend monthly treatments during the warmer months (April-November) when mosquito activity peaks in the UAE.",
  "bird-control": "Bird control prevents pigeons, mynahs, and other birds from roosting and nesting on building ledges, balconies, AC units, and signage. Solutions include stainless steel spike strips (preventing landing on narrow ledges), bird netting (blocking access to larger areas), and deterrent gel (making surfaces uncomfortable for perching). We assess your specific bird problem and recommend the most effective and humane solution for your property.",
  // APPLIANCE REPAIR - remaining
  "washing-machine-repair": "Common washing machine problems include not draining (blocked pump filter or faulty drain pump), excessive vibration (unbalanced load or worn shock absorbers), not spinning (door lock fault or motor carbon brush wear), and water leaks (door seal tear or inlet valve failure). Our technicians diagnose on-site and carry common replacement parts — drain pumps, door seals, carbon brushes, and inlet valves — for popular brands including Samsung, LG, Bosch, Siemens, and Beko.",
  "dryer-repair": "Dryer problems include not heating (failed heating element or blown thermal fuse), long drying times (blocked lint filter or vent), unusual noise (worn drum bearings or loose belt), and not tumbling (broken drive belt or motor fault). Our technicians check the electrical supply, thermal fuse, heating element, and mechanical components during diagnosis. Most repairs are completed in a single visit with parts stocked for common brands.",
  "freezer-repair": "Freezer issues include not freezing (thermostat fault, low refrigerant, or compressor failure), excessive frost buildup (defrost system malfunction), unusual noise (compressor or fan motor), and door seal failure (allowing warm air entry). Our technicians test the thermostat, defrost timer, heating element, and compressor to identify the fault. Door seal replacement and thermostat calibration are the most common fixes.",
  "cooker-repair": "Cooker and stovetop repair covers gas burner ignition failure (piezo igniter or spark electrode replacement), uneven flame (blocked burner ports), oven not heating (faulty element or thermostat), and gas smell (valve or connection leak requiring immediate attention). Our technicians are trained in both gas and electric cooker repair. For gas-related issues, we perform a safety leak test after every repair.",
  "oven-repair": "Oven problems include not heating (failed heating element — top, bottom, or fan element), inconsistent temperature (thermostat drift or faulty sensor), fan not working (motor replacement), and door not closing properly (hinge or seal replacement). Our technicians test each component systematically, replace the faulty part, and verify temperature accuracy with a probe thermometer after repair.",
  "dishwasher-repair": "Dishwasher issues include not draining (blocked filter, faulty drain pump, or kinked drain hose), not cleaning properly (clogged spray arms or low water pressure), leaking (door seal failure or loose hose connection), and not starting (door latch switch or control board fault). Our technicians clean the filter assembly, check spray arm rotation, test the pump, and inspect electrical connections during diagnosis.",
  "microwave-repair": "Microwave repair covers not heating (magnetron failure or high-voltage diode), turntable not rotating (motor or coupler replacement), sparking inside (damaged waveguide cover or metallic paint chipping), and door switch failure (preventing the unit from starting). Due to high-voltage components, microwave repair should only be done by trained technicians. Our team carries common replacement parts for popular brands.",
  "refrigerator-repair": "Refrigerator problems include not cooling (compressor failure, thermostat fault, or low refrigerant), overcooling or freezing food (thermostat miscalibration or damper stuck open), water leaking inside (blocked defrost drain), and excessive noise (condenser fan or compressor vibration). Our technicians diagnose the issue using temperature measurements and electrical testing, and carry common parts including thermostats, fans, and defrost heaters.",
  "water-dispenser-repair": "Water dispenser issues include not cooling (compressor or thermostat fault), not heating (heating element burn-out), slow water flow (clogged filter or air lock in lines), and leaking (loose bottle connection or internal tank crack). Our technicians service floor-standing and countertop dispensers from all major brands. Filter replacement, sanitization, and full system flush are included in our standard service visit.",
  "water-heater-repair-appliance": "Water heater repair covers no hot water (element failure or thermostat trip), insufficient heating (sediment-covered element or thermostat miscalibration), leaking tank (corroded anode rod or pressure relief valve failure), and unusual noise (sediment rumbling). Our technicians carry replacement elements, thermostats, and anode rods for popular brands sold in UAE. Tank integrity is assessed — if corroded through, we recommend replacement with same-visit installation.",
  // MOVERS - remaining
  "studio-moving": "Studio moving is our most compact and affordable relocation service — suitable for furnished or unfurnished studios with limited belongings. We provide a small truck, 2 movers, protective blankets and wrapping materials, furniture disassembly if needed (bed frame, small wardrobe), transport, and reassembly at destination. Most studio moves within the same city are completed in 2-3 hours.",
  "office-moving": "Office relocation requires careful handling of IT equipment (computers, monitors, printers, servers), filing cabinets with contents, modular furniture disassembly and reassembly, and coordination with building management at both locations for elevator booking and loading bay access. We pack fragile equipment in specialized boxes, label everything by department, and deploy enough movers to complete the move during a weekend to minimize business disruption.",
  "warehouse-moving": "Warehouse relocation involves pallet racking disassembly and reassembly, heavy item transport (machinery, inventory, shelving systems), forklift loading and unloading, and site cleanup after move-out. We deploy trucks rated for heavy loads, use pallet jacks and forklifts, and coordinate the move in phases to maintain operational continuity if needed. Full warehouse moves take 1-5 days depending on inventory volume.",
  "professional-packing": "Professional packing provides all materials and labor for secure packaging of your belongings — cardboard boxes in various sizes, bubble wrap for fragile items, foam sheets for glass and mirrors, wardrobe boxes for hanging clothes, and packing tape. Our packers wrap items individually, label each box by room and contents, and create an inventory list. Packing a 2-bedroom apartment typically takes 4-6 hours with 2 packers.",
  "storage-service": "Storage service provides short-term or long-term secure storage in climate-controlled warehouses across the UAE. Your items are inventoried, professionally wrapped, and stored on racking systems in a clean, dry environment monitored by security cameras. Access to retrieve items is available by appointment. Ideal during moves between properties, renovation periods, or for seasonal items you don't use year-round.",
  "furniture-moving": "Single-item or multi-piece furniture moving handles items that are too heavy or awkward for two people — sofas, dining tables, wardrobes, bed frames, pianos, and gym equipment. Our movers bring the right equipment (trolleys, straps, blankets) for the specific item, disassemble if needed for doorway clearance, transport safely, and reassemble at the destination. Available for same-building moves (between floors or rooms) and cross-city transport.",
  // GARDEN - remaining
  "lawn-mowing": "Regular lawn mowing keeps grass at the optimal 3-5cm height for UAE conditions, preventing brown patches from scalping and weed encroachment from letting grass grow too tall. Our garden teams use rotary mowers for standard lawns and cylinder mowers for premium turf, edge along borders and pathways, and collect all clippings. Weekly mowing is recommended during the growing season (October-April); bi-weekly during summer dormancy.",
  "garden-cleanup": "Garden cleanup covers leaf and debris clearing, weed removal from beds and pathways, dead plant removal, pruning of overgrown shrubs, fallen branch collection, and general garden tidying. Ideal before hosting events, after storms, or when a garden has been neglected during an absence. We haul away all green waste for proper disposal. Typical villa garden cleanup takes 3-5 hours with a 2-person team.",
  "hedge-trimming": "Hedge trimming maintains the shape, density, and health of boundary hedges, decorative hedges, and topiary. We use professional power trimmers for straight-line cuts and hand shears for detailed shaping. Proper technique includes cutting slightly wider at the base than the top to ensure lower branches receive sunlight. Most villa hedges take 1-2 hours to trim, with clipping cleanup included.",
  "tree-trimming": "Tree trimming removes dead branches, controls canopy size, improves shape, and prevents branches from interfering with buildings, power lines, or walkways. Our trained crew uses pole saws, chain saws, and hand pruners depending on branch size, making proper cuts at the branch collar to promote healing. For tall palms (date palms, washingtonia), we remove dead fronds and fruit clusters to maintain appearance and prevent falling debris.",
  "plant-maintenance": "Plant maintenance covers watering schedule adjustment based on season and plant type, fertilizer application using slow-release granules suited to UAE soil conditions, pest and disease inspection, dead-heading flowers, pruning leggy growth, mulch replenishment to retain soil moisture, and seasonal plant replacement when annuals complete their cycle. Monthly maintenance keeps indoor and outdoor plants healthy in the UAE's challenging climate.",
  "landscape-design": "Landscape design creates a functional and attractive outdoor space tailored to UAE climate conditions — drought-tolerant plant selection, efficient irrigation layout, hardscape elements (pathways, seating areas, decorative stone), shade structures, outdoor lighting, and lawn placement. Our designer visits your property, discusses your usage needs and aesthetic preferences, and provides a scaled layout drawing with plant list and cost estimate before work begins.",
  "irrigation-system": "Irrigation system installation covers drip lines for planted beds, pop-up sprinklers for lawn areas, bubblers for trees, and timer controller programming for automated watering schedules. We design the system based on your garden layout, water pressure, and plant water requirements. UAE's hard water means periodic nozzle and drip emitter replacement to prevent calcium clogging. System includes a filter, pressure regulator, and zone valves for efficient water use.",
  "artificial-grass": "Artificial grass installation involves removing existing surface material, grading and compacting the soil base, laying a weed barrier membrane, spreading and leveling a crushed aggregate base, rolling out the synthetic turf, trimming to fit edges and around obstacles, securing with landscape pins, and infilling with silica sand for blade support and weight. The result is a zero-maintenance green surface that stays usable year-round regardless of UAE heat.",
  "pool-repair": "Pool repair covers pump motor failure (overheating, noise, or not priming), filter housing cracks, plumbing leaks in underground pipes, tile and grout replacement along the waterline, pool light replacement (underwater LED), and skimmer basket or valve damage. Our technicians diagnose pool equipment issues on-site and carry common replacement parts. For major structural repairs like concrete shell cracks, we provide a separate assessment and quote.",
  // BUILDING MAINTENANCE - remaining
  "villa-maintenance": "Villa maintenance covers the regular upkeep tasks that keep a larger property in good condition — AC filter cleaning and seasonal servicing, plumbing fixture checks for leaks and drips, electrical safety testing, minor paint touch-ups, door and window hardware adjustment, garden watering system check, and pest prevention treatment. Our scheduled visits catch small issues before they become expensive repairs.",
  "apartment-maintenance": "Apartment maintenance handles the common issues that arise in daily apartment living — dripping taps, running toilets, loose door handles, sticking windows, AC filter cleaning, light bulb replacement, minor wall repairs, and bathroom silicone resealing. Our handyman visits cover a checklist of standard items plus any specific issues you want addressed. Ideal as a quarterly preventive checkup.",
  "office-maintenance": "Office maintenance ensures your workplace systems function reliably — AC performance checks, lighting replacement, plumbing fixture servicing, electrical outlet testing, door closer adjustment, ceiling tile replacement, and general facility upkeep. Recurring maintenance contracts include monthly visits with a checklist customized to your office size and equipment. Emergency call-outs for facility failures are prioritized for contract clients.",
  "commercial-maintenance": "Commercial maintenance covers retail spaces, restaurants, warehouses, and multi-unit properties with scheduled servicing of AC systems, plumbing infrastructure, electrical distribution, fire safety equipment, and general building upkeep. We provide a dedicated facility maintenance coordinator who schedules routine visits, tracks service history, and manages vendor procurement for specialized repairs outside our scope.",
  "annual-inspection": "Annual property inspection is a comprehensive review of your building's major systems — AC units (performance, drainage, electrical connections), plumbing (water pressure, leak checks, water heater condition), electrical (DB panel, wiring insulation, earth leakage devices), structural elements (wall cracks, water stains, roof condition), and exterior (paint condition, waterproofing, drainage). You receive a detailed report with photos, priority rankings, and estimated repair costs.",
  "safety-inspection": "Safety inspection covers fire alarm testing (smoke detectors, heat detectors, manual call points), fire extinguisher inspection (pressure, expiry, accessibility), emergency lighting function test, electrical earthing verification, gas leak detection (for properties with gas supply), and fire exit accessibility check. We provide a compliance report identifying any items that need attention to meet UAE civil defense safety standards.",
  "pre-purchase-inspection": "Pre-purchase property inspection gives buyers a detailed condition assessment before committing to a purchase. Our inspectors evaluate structural integrity, AC system condition and remaining lifespan, plumbing function and pipe condition, electrical safety, waterproofing effectiveness, paint and finish quality, window and door operation, and any visible defects or maintenance backlog. The report helps you negotiate the price or budget for repairs.",
  "commercial-amc": "Commercial AMC covers full-building maintenance with monthly scheduled visits, quarterly AC servicing for all units, annual fire safety inspection, plumbing and electrical system audits, pest control treatment, and 24-hour emergency response for critical failures. We assign a dedicated account manager who maintains service records, coordinates with your facility team, and provides monthly reports on work completed and upcoming scheduled items.",
  "villa-amc": "Villa AMC is our most comprehensive residential plan — quarterly AC servicing for all units, monthly garden maintenance (mowing, trimming, irrigation check), bi-annual plumbing inspection, annual electrical audit, quarterly pest control, annual deep clean, and unlimited emergency callouts with priority response. The plan covers the typical 15-20 maintenance touchpoints a villa needs annually, bundled at 20-30% less than individual service pricing.",
  "high-rise-cleaning": "High-rise building facade and window cleaning uses rope access (BMU or abseiling from rooftop anchor points) for buildings too tall for ladder or boom lift access. Our rope access technicians are IRATA certified, carry cleaning equipment in descender kits, and work systematically from top to bottom. We coordinate with building management for anchor point certification, safety exclusion zones, and resident notifications.",
  "rope-access-maintenance": "Rope access maintenance covers any exterior building work that requires harness-based access — facade painting, sealant replacement around windows, cladding repair, signage installation, external pipe repair, and waterproofing application on high-rise structures. Our IRATA-certified technicians eliminate the need for expensive scaffolding or boom lift rental, reducing project cost and setup time significantly.",

  // LIFESTYLE - remaining
  "maid-service": "Our maid service provides trained domestic cleaners for daily, weekly, or bi-weekly home visits. Each visit covers kitchen cleaning, bathroom sanitization, floor mopping, surface dusting, bed making, trash removal, and general tidying. We assign the same cleaner to your home for consistency — they learn your preferences and work more efficiently with each visit. All cleaners carry valid UAE residency and work permits.",
  "ironing-service": "Ironing service covers shirts, trousers, dresses, traditional garments, bed linens, and tablecloths. Our staff use professional steam irons with adjustable temperature settings for different fabrics (cotton, silk, polyester, linen). Items are folded and organized by category for easy storage. Available as a standalone service or add-on to a regular cleaning visit. Typical household ironing basket takes 1-2 hours.",
  "laundry-service": "Laundry service covers washing, drying, folding, and optional delivery of household clothing, bed linens, towels, and curtains. We sort by fabric type and color, use appropriate wash cycles and detergents, and return items folded and organized. For delicate items, we hand-wash or use gentle cycles as needed. Pickup and delivery available for regular customers on scheduled routes.",
  "office-support": "Office support services cover daily or weekly tasks that keep your workspace running smoothly — reception area tidying, meeting room preparation and post-meeting reset, pantry restocking and cleaning, plant watering, mail sorting, and general administrative support. Available as recurring scheduled visits or on-demand booking for specific events and busy periods.",

};

export function getServiceAbout(slug: string): string {
  return SERVICE_ABOUT[slug] || "";
}
